public boolean findNode(TreeNode root, int k, Set<Integer> nodes) {
    if (root == null) return false;
    if (nodes.contains(k - root.val)) return true;
    nodes.add(root.val);
    return findNode(root.left, k, nodes) || findNode(root.right, k, nodes);
}
